// V16.3: SAP直接查询全字段(含描述)，on_hand按批次/库位粒度
// 第一批前加DELETE清除当天旧快照
const allInput = $input.all().map(r => r.json);
const filteredRows = allInput.filter(r => r.item_code && String(r.item_code).trim() !== '');

// 按item_code+whs_code+bin_code+batch_number去重，SAP LEFT JOIN可能产生重复行
const seen = new Set();
const rawRows = filteredRows.filter(r => {
  const key = String(r.item_code) + '|' + String(r.whs_code||'') + '|' + String(r.bin_code||'') + '|' + String(r.batch_number||'');
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

if (rawRows.length === 0) {
  return [{ json: { _skip: true, success: true, message: '期初库存: SAP无非零库存数据', count: 0 } }];
}

const today = new Date().toISOString().substring(0, 10);
const batchSize = 200;
const batches = [];
const esc = (v) => { if(v===null||v===undefined) return 'NULL'; let s=String(v).substring(0,500); s=s.replace(/�/g,''); s=s.replace(/\\/g,'\\\\').replace(/'/g,"''"); return "'"+s+"'"; };
const num = (v) => Number(v) || 0;
const dt = (v) => { if(!v) return 'NULL'; const s=String(v); const m=s.match(/^(\d{4}-\d{2}-\d{2})/); return m ? "'"+m[1]+"'" : 'NULL'; };

for (let i = 0; i < rawRows.length; i += batchSize) {
  const batch = rawRows.slice(i, i + batchSize);
  const values = batch.map(r => {
    return `(${esc($env.DP_COMPANY_CODE)},${esc(today)},${esc(r.item_code)},${esc(r.item_name||'')},${esc(r.foreign_name||'')},${esc(r.item_group||'')},${esc(r.uom||'')},${esc(r.whs_code)},${esc(r.whs_name||'')},${esc(r.bin_code||'Default Bin')},${esc(r.bin_enabled||'N')},${esc(r.batch_managed||'N')},${esc(r.batch_number)},${esc(r.mfr_batch)},${esc(r.lot_number)},${dt(r.mfr_date)},${dt(r.exp_date)},${dt(r.in_date)},${num(r.on_hand)},${num(r.bin_qty)},${num(r.batch_qty)},${num(r.bin_max_level)},${num(r.avg_price)},${num(r.stock_value)},${num(r.total_on_hand)},${num(r.committed_qty)},${num(r.ordered_qty)},NOW())`;
  }).join(',\n');
  // 第一批前加DELETE清除当天旧快照，避免多次导入累积重复
  const prefix = (i === 0) ? 'DELETE FROM wms.wms_stock_snapshot WHERE snapshot_date = CURRENT_DATE; ' : '';
  const sql = prefix + `INSERT INTO wms.wms_stock_snapshot (company_code, snapshot_date,item_code,item_name,foreign_name,item_group,uom,whs_code,whs_name,bin_code,bin_enabled,batch_managed,batch_number,mfr_batch,lot_number,mfr_date,exp_date,in_date,on_hand,bin_qty,batch_qty,bin_max_level,avg_price,stock_value,total_on_hand,committed_qty,ordered_qty,synced_at) VALUES ${values}`;
  batches.push({ json: { _skip: false, sql, batch_num: Math.floor(i/batchSize)+1, count: batch.length, _total: rawRows.length } });
}
return batches;

// V16.1: 汇总期初库存导入结果
const items = $input.all();
const first = items[0] ? items[0].json : {};
const total = first._total || 0;
return { json: { success: true, message: '期初库存导入完成: ' + total + ' 条写入快照(描述字段已从缓存补全)', count: total } };
